// // This module implements a 4-bit shift register with load and shift capabilities. On the rising edge of the clock, if the load signal is asserted, the register will shift the current register contents to the right by one position while filling the most significant bit with zero; otherwise, if the shift signal is asserted, it will load the input values.
module top_module(clk, load, in, shift, out);input clk, load, shift;
    input [3:0] in;
    output [3:0] out;
    reg [3:0] reg_out;

    always @(posedge clk) begin
        if (load) begin
            reg_out <= in;
        end else if (shift) begin
            reg_out <= {reg_out[2:0], 1'b0};
        end
    end

    assign out = reg_out;
endmodule
